<body class="antialiased">
    <div class="relative flex items-center justify-center min-h-screen bg-[#FDFDFC] dark:bg-[#0a0a0a] p-6 lg:p-8">
        <!-- Background Decorative Elements -->
        <div class="absolute inset-0 overflow-hidden pointer-events-none">
            <div class="absolute -top-40 -right-40 w-80 h-80 bg-[#fff2f2] dark:bg-[#1D0002] rounded-full blur-3xl opacity-50"></div>
            <div class="absolute -bottom-40 -left-40 w-80 h-80 bg-[#fff2f2] dark:bg-[#1D0002] rounded-full blur-3xl opacity-50"></div>
        </div>

        <div class="w-full max-w-[335px] lg:max-w-4xl">
            <!-- Header -->
            <header class="w-full text-sm mb-6">
                <nav class="flex items-center justify-end gap-4">
                    <a href="/login" class="inline-block px-5 py-1.5 dark:text-[#EDEDEC] text-[#1b1b18] border border-transparent hover:border-[#19140035] dark:hover:border-[#3E3E3A] rounded-sm text-sm leading-normal font-medium transition">Log in</a>
                    <a href="/register" class="inline-block px-5 py-1.5 dark:text-[#EDEDEC] border-[#19140035] hover:border-[#1915014a] border text-[#1b1b18] dark:border-[#3E3E3A] dark:hover:border-[#62605b] rounded-sm text-sm leading-normal font-medium transition">Register</a>
                </nav>
            </header>

            <!-- Main Card -->
            <div class="flex flex-col-reverse lg:flex-row w-full transition-all duration-300 ease-in-out">
                <!-- Form Section -->
                <div class="text-[13px] leading-[20px] flex-1 p-6 pb-6 lg:p-20 lg:pb-10 bg-white dark:bg-[#161615] dark:text-[#EDEDEC] shadow-[inset_0px_0px_0px_1px_rgba(26,26,0,0.16)] dark:shadow-[inset_0px_0px_0px_1px_#fffaed2d] rounded-bl-lg rounded-br-lg lg:rounded-tl-lg lg:rounded-br-none">
                    <div class="max-w-md mx-auto lg:mx-0">
                        <h1 class="text-lg font-semibold mb-1">Create an account</h1>
                        <p class="mb-6 text-[#706f6c] dark:text-[#A1A09A] text-sm">Get started with your new account</p>

                        <!-- Registration Form -->
                        <form method="POST" action="/register" class="space-y-5">
                            @csrf
                            <div>
                                <label for="name" class="block text-sm font-medium text-[#1b1b18] dark:text-[#EDEDEC] mb-1">Full name</label>
                                <input id="name" type="text" name="name" value="{{ old('name') }}" required autofocus
                                    class="w-full px-4 py-2 rounded-md border border-[#e3e3e0] dark:border-[#3E3E3A] bg-white dark:bg-[#0a0a0a] text-[#1b1b18] dark:text-[#EDEDEC] text-sm focus:outline-none focus:ring-1 focus:ring-blue-300 dark:focus:ring-blue-700 transition">
                                @error('name')
                                    <span class="text-xs text-[#f53003] dark:text-[#FF4433] mt-1 block">{{ $message }}</span>
                                @enderror
                            </div>

                            <div>
                                <label for="email" class="block text-sm font-medium text-[#1b1b18] dark:text-[#EDEDEC] mb-1">Email address</label>
                                <input id="email" type="email" name="email" value="{{ old('email') }}" required
                                    class="w-full px-4 py-2 rounded-md border border-[#e3e3e0] dark:border-[#3E3E3A] bg-white dark:bg-[#0a0a0a] text-[#1b1b18] dark:text-[#EDEDEC] text-sm focus:outline-none focus:ring-1 focus:ring-blue-300 dark:focus:ring-blue-700 transition">
                                @error('email')
                                    <span class="text-xs text-[#f53003] dark:text-[#FF4433] mt-1 block">{{ $message }}</span>
                                @enderror
                            </div>

                            <div>
                                <label for="password" class="block text-sm font-medium text-[#1b1b18] dark:text-[#EDEDEC] mb-1">Password</label>
                                <input id="password" type="password" name="password" required
                                    class="w-full px-4 py-2 rounded-md border border-[#e3e3e0] dark:border-[#3E3E3A] bg-white dark:bg-[#0a0a0a] text-[#1b1b18] dark:text-[#EDEDEC] text-sm focus:outline-none focus:ring-1 focus:ring-blue-300 dark:focus:ring-blue-700 transition">
                                @error('password')
                                    <span class="text-xs text-[#f53003] dark:text-[#FF4433] mt-1 block">{{ $message }}</span>
                                @enderror
                            </div>

                            <div>
                                <label for="password_confirmation" class="block text-sm font-medium text-[#1b1b18] dark:text-[#EDEDEC] mb-1">Confirm password</label>
                                <input id="password_confirmation" type="password" name="password_confirmation" required
                                    class="w-full px-4 py-2 rounded-md border border-[#e3e3e0] dark:border-[#3E3E3A] bg-white dark:bg-[#0a0a0a] text-[#1b1b18] dark:text-[#EDEDEC] text-sm focus:outline-none focus:ring-1 focus:ring-blue-300 dark:focus:ring-blue-700 transition">
                            </div>

                            <button type="submit" 
                                class="w-full flex justify-center py-2.5 px-4 border border-transparent rounded-md shadow-sm text-sm font-medium text-white bg-[#1b1b18] hover:bg-black dark:bg-[#eeeeec] dark:text-[#1C1C1A] dark:hover:bg-white transition focus:outline-none focus:ring-2 focus:ring-offset-2 focus:ring-[#f53003] dark:focus:ring-[#FF4433]">
                                Register
                            </button>
                        </form>

                        <p class="mt-6 text-center text-sm text-[#706f6c] dark:text-[#A1A09A]">
                            Already have an account?
                            <a href="/login" class="font-medium text-[#f53003] dark:text-[#FF4433] hover:underline">Sign in</a>
                        </p>

                        <p class="mt-6 text-xs text-[#706f6c] dark:text-[#A1A09A]">
                            v{{ app()->version() }}
                            <a href="https://github.com/laravel/framework/blob/13.x/CHANGELOG.md" target="_blank" class="inline-flex items-center gap-1 font-medium underline underline-offset-4 text-[#f53003] dark:text-[#FF4433] ml-1">
                                <span>View changelog</span>
                                <svg width="10" height="11" viewBox="0 0 10 11" fill="none" xmlns="http://www.w3.org/2000/svg" class="w-2.5 h-2.5">
                                    <path d="M7.70833 6.95834V2.79167H3.54167M2.5 8L7.5 3.00001" stroke="currentColor" stroke-linecap="square"/>
                                </svg>
                            </a>
                        </p>
                    </div>
                </div>

                <!-- Graphic Section - identical to welcome page -->
                <div class="bg-[#fff2f2] dark:bg-[#1D0002] relative lg:-ml-px -mb-px lg:mb-0 rounded-t-lg lg:rounded-t-none lg:rounded-r-lg aspect-[335/364] lg:aspect-auto w-full lg:w-[438px] shrink-0 overflow-hidden">
                    <!-- Laravel Logo -->
                    <svg class="w-full text-[#F53003] dark:text-[#F61500] transition-all translate-y-0 opacity-100 max-w-none duration-750" viewBox="0 0 438 104" fill="none" xmlns="http://www.w3.org/2000/svg">
